const SOCEX_UNITS=[
 {id:"ex1",n:1,week:1,title:"The Two Papers and the Three Skills",mins:150,icon:"Target",
  summary:"How Paper 1 and Paper 2 are built, the marks each question carries, and the AO1/AO2/AO3 skills your students are marked on.",
  keyWords:["Paper 1","Paper 2","AO1","AO2","AO3","levels of response"],
  sections:[
   {h:"Paper 1 and Paper 2 at a glance",art:"target",p:[
    "IGCSE Sociology (0495) has two papers. Paper 1 covers Theory and Methods, Culture and Identity, and Social Inequality. Paper 2 covers Family, Education, and Crime, Deviance and Social Control. Knowing the shape of each paper is the first thing to teach.",
    "On Paper 1 the source-based Question 1 (Research Methods) is compulsory, then students choose Question 2 (Identity) OR Question 3 (Inequality). On Paper 2 students answer two questions from a choice of three (Family, Education, Crime). Each big question is worth 40 marks."],
    ex:{t:"Example \u2014 reading the front of the paper with students",b:["Paper 1: do Q1 (Research Methods, compulsory) + choose Q2 or Q3.","Paper 2: choose two of Q1 Family, Q2 Education, Q3 Crime.","Each chosen question is a 40-mark ladder of parts, from [2] up to [14]."]}},
   {h:"The ladder of parts inside each question",art:"steps",p:[
    "Each 40-mark question climbs a ladder: short (a) parts worth [2], mid parts worth [4] and [6], and the two big essays worth [8] (Discuss) and [10], [12] or [14] (Evaluate). The command word and the mark in brackets change at every rung.",
    "Teaching students to recognise the rung they are on \u2014 and to spend time in proportion to the marks \u2014 is one of the highest-value exam skills. A student who spends equal time on a [2] and a [14] will run out of time where it matters most."],
    ex:{t:"Example \u2014 the Paper 1 Research Methods ladder",b:["(a)(i) Identify [2] \u00B7 (a)(ii) Explain two reasons [4] \u00B7 (a)(iii) Explain three reasons [6].","(b) Identify [2] \u00B7 (c) Explain one strength and one limitation [4].","(d) Evaluate [10] \u00B7 (e) methods essay [12]. The marks tell you how much to write."]}},
   {h:"The three skills: AO1, AO2, AO3",art:"steps",p:[
    "Students are marked on three skills. AO1 is knowledge (terms, theories, studies). AO2 is application (using that knowledge to answer THIS question). AO3 is analysis and evaluation (weighing views and judging). The big essays reward AO3 most.",
    "The practical message for students: knowing the content is necessary but not sufficient. The marks at the top come from applying knowledge to the exact question and from building a balanced, judged argument \u2014 not from writing everything they know."],
    ex:{t:"Example \u2014 one idea across the three skills",b:["AO1 (know): \u2018Labelling theory says being called deviant can shape behaviour.\u2019","AO2 (apply): linking that to the specific question asked.","AO3 (judge): weighing labelling against other explanations and reaching a conclusion."]}},
   {h:"Long answers are marked in LEVELS",art:"mark",p:[
    "The [8], [10], [12] and [14] answers are marked in levels, not by counting ticks. The examiner reads the whole answer and matches it to a level descriptor: a one-sided list sits low; a two-sided, developed, concluded argument sits high.",
    "This is why structure matters so much. Two students with the same knowledge can land in different levels purely because one organised the answer into signalled, developed paragraphs with a conclusion and the other did not."],
    ex:{t:"Example \u2014 what moves an answer up a level",b:["Low: a list of points, one side only, no conclusion.","Middle: two sides, but points under-developed.","High: two sides, each developed with evidence, plus a reasoned judgement."]}},
  ],
  activity:"Print the front page and Question 1 of Paper 1. With a colleague, label every part with its command word and mark. Discuss how many minutes you would advise a student to spend on each.",
  check:[
   {q:"On Paper 1, which question is compulsory?",o:["Question 3 (Inequality)","None \u2014 all optional","Question 1 (Research Methods)","Question 2 (Identity)"],a:2},
   {q:"AO3 in the 0495 papers rewards\u2026",o:["Neat handwriting","Length alone","Only factual recall","Analysis and evaluation"],a:3},
   {q:"The long answers are marked by\u2026",o:["Counting words","Timing the student","Matching the whole answer to a level","Counting ticks per fact"],a:2},
  ]},
 {id:"ex2",n:2,week:1,title:"Identify, Define and Give (the [2] marks)",mins:150,icon:"ClipboardCheck",
  summary:"How to coach students through the short-answer marks so they score full marks fast and free up time for the essays.",
  keyWords:["Identify","Define","Give","partial definition","context"],
  sections:[
   {h:"Identify and Give: name it, stop there",art:"target",p:[
    "Identify and Give questions are worth [2] and want exact items, nothing more. The specimen mark schemes are explicit: adding explanation or definitions earns no extra marks and wastes time. In one specimen, \u2018Identify two types of question\u2019 scored full marks with just two named items.",
    "Coach students to answer in a few words and move on. The discipline of NOT over-writing here is what protects their time for the [14] essay later."],
    ex:{t:"Example \u2014 full marks in a phrase",b:["\u2018Give two examples of surveillance used for controlling crime.\u2019 [2] \u2192 CCTV and police helicopters.","No description needed \u2014 the command is \u2018give\u2019, so accurate examples alone score.","Extra sentences here score nothing and cost time."]}},
   {h:"Context is a trap on Give questions",art:"mark",p:[
    "The commonest way students lose an easy mark is ignoring the context in the question. In a specimen \u2018Give two negative sanctions used in the family\u2019 [2], one answer offered \u2018being sent to prison\u2019 \u2014 a real sanction, but not one used in the family, so it scored only 1 of 2.",
    "Teach students to underline the context words (\u2018in the family\u2019, \u2018to control crime\u2019) before answering, and to check each example actually fits that context."],
    ex:{t:"Example \u2014 the context check",b:["Question says \u2018negative sanctions used in the family\u2019.","\u2018Being told off by parents\u2019 fits the family \u2014 credited.","\u2018Being sent to prison\u2019 does not fit the family \u2014 not credited."]}},
   {h:"Define: two elements, not one",art:"steps",p:[
    "Define questions ([2]) need the full meaning of the term. The mark schemes distinguish a full definition (two elements) from a \u2018partial\u2019 one (a bare example), which scores only one mark. A specimen defined feminism as a theory (element one) about gender inequality (element two) \u2014 full marks.",
    "Coach the two-element habit: state what kind of thing the term is, then add its defining feature. An example on its own is not a definition."],
    ex:{t:"Example \u2014 a full two-element definition",b:["\u2018Deviance\u2019 = breaking society\u2019s norms and values (element one) \u2014 e.g. stealing from a shop (element two, an example that shows understanding).","\u2018Postmodernism\u2019 = a sociological theory (element one) about how society has changed beyond modernity (element two).","Both score 2/2 because each has two clear elements."]}},
   {h:"Coaching the short answers",art:"write",p:[
    "The teaching goal is speed and accuracy: students should treat [2] parts as quick wins. A useful class routine is to time students answering five [2] questions in three minutes, then mark against the specimen standard.",
    "Reinforce the three rules: name exactly what is asked, respect the context, and for Define give two elements. Then move on \u2014 the marks are won by precision, not volume."],
    ex:{t:"Example \u2014 a three-minute drill",b:["Show five [2] questions on the board.","Students write only the exact items \u2014 no sentences.","Mark together against the specimen: precision, context, two-element definitions."]}},
  ],
  activity:"Write five [2] questions from across Papers 1 and 2 (a mix of Identify, Give and Define). Draft the full-mark answer for each, then a common partial answer, and note exactly why it drops a mark.",
  check:[
   {q:"A \u2018partial\u2019 definition scores\u2026",o:["3 marks","Full marks","1 mark (missing the full meaning)","0 always"],a:2},
   {q:"On a Give question, the fastest route to full marks is\u2026",o:["Writing a paragraph","Adding definitions","Explaining each example","Naming exact items that fit the context"],a:3},
   {q:"\u2018Being sent to prison\u2019 failed as a family sanction because it\u2026",o:["Was spelt wrong","Did not fit the question\u2019s context","Was a positive sanction","Was too short"],a:1},
  ]},
 {id:"ex3",n:3,week:2,title:"Explain [4] and [6]: Teaching Developed Points",mins:150,icon:"Lightbulb",
  summary:"How to move students from describing to explaining, using the 'because' habit, signal words and one-mark-per-development structure.",
  keyWords:["Explain","development","because","signal words","point plus reason"],
  sections:[
   {h:"The [4] Explain: two points, each developed",art:"build",p:[
    "A [4] Explain wants two points, each worth an identification mark plus a development mark. The specimen \u2018Explain two reasons why in-depth interviews were useful\u2019 [4] scored 4/4 by naming a useful feature in the first sentence, then developing it with a \u2018because\u2019 reason linked to qualitative data.",
    "The reliable structure is: first sentence names the point (1 mark); the next sentence develops it with a reason or link (1 mark). Two such mini-paragraphs = full marks."],
    ex:{t:"Example \u2014 the [4] structure",b:["Point: in-depth interviews let people give detail in their own words.","Development: because open questions produce rich qualitative data about thoughts and feelings.","Repeat for a second, clearly separate point. 2 + 2 = 4."]}},
   {h:"The [6] Explain: three developed points",art:"build",p:[
    "A [6] Explain wants three points, each identified and developed. The specimen \u2018Explain three reasons why poverty might lead to crime\u2019 [6] scored 6/6 with three signalled paragraphs, each naming a reason (underclass, material deprivation, status frustration) and explaining it with a named sociologist (Murray, Cohen).",
    "The teaching pattern is identical each time: signal the point, then develop with a reason, study or example. Students who name three points but develop none score only three of six."],
    ex:{t:"Structural analysis \u2014 poverty and crime [6] (scored 6/6)",b:["Point 1: underclass (Murray) \u2014 developed via poor socialisation and benefit dependency. [2]","Point 2: material deprivation (Marxists) \u2014 developed via lacking money/food \u2192 shoplifting. [2]","Point 3: status frustration (Cohen) \u2014 developed via resentment at unfairness. [2]","Three signalled, developed paragraphs = full marks."]}},
   {h:"The 'because' habit and signal words",art:"talk",p:[
    "The single most repeated tip in the mark schemes is to use the word \u2018because\u2019: it forces development and turns description into explanation. The second habit is signalling \u2014 \u2018One reason\u2026 A second reason\u2026 A third reason\u2026\u2019 \u2014 so the examiner can see each separate point.",
    "When points are not signalled, examiners struggle to separate them. In one specimen the lack of signal words meant a valid third point could not be credited for development."],
    ex:{t:"Example \u2014 turning description into explanation",b:["Describe: \u2018Official statistics measure crime rates.\u2019 (states what)","Explain: \u2018Official statistics measure crime rates BECAUSE they are quantitative data in the form of numbers.\u2019 (states why)","The word \u2018because\u2019 is what earns the development mark."]}},
   {h:"Common ways students lose Explain marks",art:"mark",p:[
    "The specimen commentaries name the same faults repeatedly: identifying the right number of points but not developing each; letting points overlap by not paragraphing; and describing rather than explaining. Each of these caps the mark below full.",
    "A useful class exercise is to give students a mid-scoring specimen answer and ask them to find the undeveloped point and add the missing \u2018because\u2019. This trains the exact skill examiners reward."],
    ex:{t:"Example \u2014 the 5/6 answer and its fix",b:["A specimen \u2018Explain three ways identity can be chosen\u2019 [6] scored 5/6.","The third point (interest-based networks) was named but not developed.","Fix: add one sentence explaining HOW that lets people choose identity \u2192 6/6."]}},
  ],
  activity:"Take a [6] Explain question from Paper 2. Write a deliberately weak version where the third point is named but not developed. Swap with a colleague and improve each other\u2019s third point to full marks.",
  check:[
   {q:"In a [6] Explain, three points but no development scores about\u2026",o:["3 of 6 (identification only)","5 of 6","0 of 6","6 of 6"],a:0},
   {q:"The mark-scheme\u2019s favourite word for forcing explanation is\u2026",o:["finally","however","because","therefore"],a:2},
   {q:"Signal words like \u2018One reason\u2026 A second reason\u2026\u2019 help by\u2026",o:["Adding length","Replacing development","Defining terms","Letting the examiner separate each point"],a:3},
  ]},
 {id:"ex4",n:4,week:2,title:"Discuss [8]: Coaching the Mini-Essay",mins:150,icon:"MessageSquare",
  summary:"How to teach the [8] Discuss: three deeply developed points, brief framing, and no wasted introductions or evaluation.",
  keyWords:["Discuss","three developed points","depth over breadth","evidence","no evaluation"],
  sections:[
   {h:"What [8] Discuss actually demands",art:"weigh",p:[
    "The [8] Discuss part asks for \u2018at least three developed points with evidence\u2019. The crucial difference from a [6] Explain is depth: the specimen commentary states part (e) answers need \u2018a greater level of development (evidence and analysis)\u2019 because it is a higher-tariff question.",
    "So the teaching target is three points, each a full paragraph with a study, statistic or worked example \u2014 not more points, but deeper ones."],
    ex:{t:"Structural analysis \u2014 changing family functions [8] (full marks)",b:["Point 1: reproduction \u2014 developed with \u2018DINK families\u2019 evidence from Beijing.","Point 2: socialisation \u2014 developed via nurseries and children\u2019s media taking over.","Point 3: emotional care \u2014 developed via care homes for the elderly.","Three deep, evidenced paragraphs = 8/8."]}},
   {h:"Keep framing brief; don\u2019t evaluate unless asked",art:"mark",p:[
    "A repeated specimen warning: do not waste time on long introductions or conclusions in an [8] Discuss, and do not criticise the view \u2014 there are no marks for evaluation at this tier. Every sentence should develop one of the three points.",
    "In one specimen the opening two sentences were unnecessary description; the examiner noted the student could have gone straight to showing understanding of the key term with a theory link."],
    ex:{t:"Example \u2014 trimming the wasted opening",b:["Weak: two sentences re-defining basic terms before starting.","Better: one short sentence showing you understand the key term (e.g. \u2018relative\u2019) with a theory link (interactionism), then straight into Point 1.","Save the words for developing the three points."]}},
   {h:"Depth: developing a point fully",art:"build",p:[
    "A point is \u2018developed\u2019 when it is explained AND supported. In the specimen \u2018Discuss the view that crime and deviance are relative\u2019 [8], the strongest points paired a claim (deviance depends on situation) with a worked example (a punch is fine in a boxing ring, criminal in the street) and an explanation of WHY.",
    "Where the same specimen only named a point without explaining why, it lost development. Teach students to always add the \u2018which means\u2026\u2019 or \u2018because\u2026\u2019 that turns a claim into analysis."],
    ex:{t:"Structural analysis \u2014 crime is relative [8]",b:["Situation: same act, different context, different judgement \u2014 explain WHY the street version is treated as assault.","Time/era: smoking once a norm, now restricted and often deviant.","Culture: acts like adultery treated very differently across societies.","Marks follow the paragraphs that explain, not just assert."]}},
   {h:"A repeatable [8] template for students",art:"write",p:[
    "Give students a simple template: one-sentence framing of the key term; then three paragraphs, each = point + development + evidence/example. No long intro, no conclusion needed, no criticism of the view.",
    "Drilling this shape means students can plan an [8] answer in under a minute and spend their time on the development that actually scores."],
    ex:{t:"Example \u2014 the [8] plan on a sticky note",b:["Framing: define the key term in one sentence + name the relevant theory.","P1 / P2 / P3: each a point + \u2018because/which means\u2026\u2019 + an example or study.","Stop. No evaluation, no long conclusion \u2014 the marks are in the three developed points."]}},
  ],
  activity:"Choose an [8] Discuss question. Plan three points on a sticky note, each with an example. Then write only the third paragraph in full, aiming for clear point + development + evidence.",
  check:[
   {q:"Compared with a [6] Explain, an [8] Discuss needs\u2026",o:["Evaluation of the view","Greater development (evidence and analysis)","A long introduction","More points but shallower"],a:1},
   {q:"In an [8] Discuss, criticising the view earns\u2026",o:["No marks (evaluation isn\u2019t required)","Full marks","Half marks","Bonus marks"],a:0},
   {q:"A point counts as \u2018developed\u2019 when it is\u2026",o:["Named only","Written in bold","Explained and supported with evidence","Repeated twice"],a:2},
  ]},
 {id:"ex5",n:5,week:3,title:"Evaluate [10\u201314]: The Top-Band Essay",mins:150,icon:"Sparkles",
  summary:"How to teach the highest-mark question: the for/against/conclusion rubric, developed paragraphs, and the judgement that reaches the top level.",
  keyWords:["Evaluate","rubric","arguments for and against","conclusion","levels of response"],
  sections:[
   {h:"The rubric is printed \u2014 teach students to obey it",art:"weigh",p:[
    "Every Evaluate question prints its rubric: \u2018at least [two or three] arguments for the view and [two or three] against, and a conclusion\u2019. Meeting every element is the entry ticket to the top level. A one-sided answer, or one with no conclusion, cannot reach it however knowledgeable.",
    "The first thing to teach is rubric-reading: count how many arguments each side needs, and plan a paragraph for each plus a conclusion, before writing a word."],
    ex:{t:"Example \u2014 turning the rubric into a plan",b:["Rubric: three for, three against, a conclusion.","Plan: 3 \u2018for\u2019 paragraphs + 3 \u2018against\u2019 paragraphs + 1 judgement.","Seven planned paragraphs before any writing \u2014 that is the top-band shape."]}},
   {h:"Structural analysis of a 12/14 Evaluate",art:"build",p:[
    "In the specimen \u2018Evaluate the view that gender is the main influence on identity\u2019 [14], the answer scored 12/14 by giving three developed FOR paragraphs (primary socialisation with Oakley\u2019s canalisation and manipulation; secondary socialisation via school and peer pressure; the gendered division of labour with vertical and horizontal segregation) and three AGAINST (other influences such as class and age).",
    "It reached Level 4 because it met the rubric, named studies (Oakley, Bourdieu), used precise concepts, and linked back to \u2018identity\u2019 throughout. It missed the top of the level because one \u2018against\u2019 paragraph was less developed and its link to identity was left implicit."],
    ex:{t:"Structural analysis \u2014 gender and identity [14] (12/14)",b:["FOR: primary socialisation (Oakley) \u00B7 secondary socialisation (school, peers) \u00B7 gendered division of labour (segregation).","AGAINST: class, age, and changing choice over identity.","CONCLUSION: identity is now more chosen; class and age matter as much as gender.","Lost 2 marks: one against-paragraph under-developed; one link to \u2018identity\u2019 left implicit."]}},
   {h:"What lifts an Evaluate into the top level",art:"talk",p:[
    "The specimen top-band answers share features you can teach directly: they name sociologists and studies (Oakley, Cohen, Murray, Becker), use precise concepts (canalisation, status frustration, patriarchy, deterrence), develop every paragraph to a similar depth, and link each argument explicitly to the exact wording of the question.",
    "Above all they end with a genuine judgement \u2014 not a summary. A conclusion that actually weighs the evidence and decides \u2018to what extent\u2019 is what separates the top level from the one below."],
    ex:{t:"Example \u2014 a judging conclusion vs a summarising one",b:["Summary (weaker): \u2018So there are arguments on both sides.\u2019","Judgement (stronger): \u2018Overall gender remains influential, but identity is now more chosen and class and age matter as much \u2014 so gender is not the single main influence.\u2019","The second decides; the first only restates."]}},
   {h:"Coaching the conclusion and the links",art:"write",p:[
    "Two coachable habits close the gap to full marks. First, the running link: end each paragraph by connecting it back to the question\u2019s key word (here, \u2018identity\u2019). Second, the weighed judgement: the conclusion should say how far the view holds and why, referring to the strongest evidence.",
    "A good drill: give students a strong two-sided answer with a weak one-line conclusion and ask them to rewrite the conclusion so it weighs the evidence and decides. This is often the difference between Level 3 and Level 4."],
    ex:{t:"Example \u2014 the capital punishment [14] (13/14)",b:["FOR: deterrence and the \u2018get tough\u2019 / zero-tolerance argument.","AGAINST: discriminatory sentencing (Marxist), prisons as \u2018universities of crime\u2019, and rehabilitation reaching more offenders.","CONCLUSION: a balanced judgement acknowledging both the deterrent case and the serious criticisms.","Near-full marks because every paragraph is developed and the conclusion genuinely weighs the sides."]}},
  ],
  activity:"Take a [14] Evaluate question and plan seven paragraphs (three for, three against, one conclusion). Write the conclusion in full so that it weighs the evidence and reaches a clear, justified judgement.",
  check:[
   {q:"To reach the top level, an Evaluate answer must include\u2026",o:["A long introduction","Both sides AND a conclusion (the full rubric)","One strong side only","Just named studies"],a:1},
   {q:"The gender-and-identity specimen lost 2 marks mainly because\u2026",o:["It had no knowledge","It had no examples","One paragraph was under-developed and a link was implicit","It was one-sided"],a:2},
   {q:"A top-band conclusion should\u2026",o:["Repeat the question","Summarise without deciding","Weigh the evidence and make a judgement","Introduce a new point"],a:2},
  ]},
 {id:"ex6",n:6,week:3,title:"The Paper 1 Methods Essay [12\u201313]",mins:150,icon:"FlaskConical",
  summary:"How to coach the research-methods design question: two primary methods with sampling, one secondary source, and justification throughout.",
  keyWords:["methods essay","primary methods","sampling","secondary evidence","justification","application to context"],
  sections:[
   {h:"What the methods essay asks",art:"steps",p:[
    "The Paper 1 methods essay (worth [12] or [13]) asks students to explain the research methods and evidence they would choose to investigate a given topic, and to justify their choices. The rubric requires two primary methods with relevant sampling and one source of secondary evidence.",
    "It is marked on three criteria: the methods and evidence chosen, the reasons for the choices, and the application to the context (the specific topic). Missing any one of these caps the level."],
    ex:{t:"Example \u2014 the rubric of the methods essay",b:["Two primary methods (e.g. an online survey and a group interview), each with a sampling method and size.","One source of secondary evidence (e.g. past newspaper reports).","Justify every choice AND link it to the exact topic being investigated."]}},
   {h:"Justify, don\u2019t just describe",art:"mark",p:[
    "The specimen scored 10/12 partly because one sample was merely described, not justified, and there was no reference to reliability or generalisability where it was relevant. The examiners are clear: describing a choice is not the same as justifying it, and criticising your own choices earns nothing here.",
    "Teach students to attach a \u2018because\u2019 to every decision: why this method, why this sample size, why this sampling technique, why this secondary source \u2014 each linked to the topic."],
    ex:{t:"Example \u2014 describe vs justify a sample",b:["Describe: \u2018My sample is 500 young people aged 13\u201325.\u2019","Justify: \u2018\u2026 stratified by gender BECAUSE it makes the sample more representative of young people, improving generalisability.\u2019","The justification and the concept (generalisability) are what lift the level."]}},
   {h:"Application to context is a separate skill",art:"target",p:[
    "The third marking criterion is application to context. The specimen answer lost ground because its secondary evidence was about \u2018people\u2019 in general rather than the specific group (young people) in the question. Every method, sample and source must be tied to the exact topic.",
    "A simple discipline: after each choice, students should write one clause that names the topic (\u2018\u2026 how young people use the internet\u2019). If a paragraph never names the topic, it is not applied."],
    ex:{t:"Example \u2014 keeping the topic in view",b:["Survey: closed questions about how young people spend time online.","Group interview: chosen because it is less threatening for young people specifically.","Secondary source: must also be about young people, not people in general."]}},
   {h:"Coaching a full-mark methods essay",art:"write",p:[
    "The teaching template: for each primary method \u2014 name it, justify it (validity/reliability), give a sample with size and technique, justify the sample, and link to the topic. Then one secondary source, justified and linked. No long introduction or conclusion.",
    "Drill the three criteria as a checklist students run over their own answer: chosen methods present? every choice justified? every part linked to the exact context? If all three are yes, the answer sits in the top level."],
    ex:{t:"Example \u2014 the methods-essay checklist",b:["Two primary methods, each justified with a concept (validity, reliability).","Sampling: size + technique + justification for each.","One secondary source, justified and tied to the topic. All linked to the exact context."]}},
  ],
  activity:"Set a methods-essay topic (e.g. \u2018how students use social media\u2019). Draft the plan: two primary methods with justified samples and one secondary source, ensuring each line names the topic and attaches a reason.",
  check:[
   {q:"The methods essay requires which combination?",o:["Three secondary sources","Two primary methods with sampling + one secondary source","One method only","No sampling"],a:1},
   {q:"The specimen lost marks partly because a sample was\u2026",o:["Missing entirely","Described but not justified","Too large","Off-topic only"],a:1},
   {q:"\u2018Application to context\u2019 means every choice is linked to\u2026",o:["The exact topic being investigated","The longest method","The teacher\u2019s opinion","The mark scheme wording"],a:0},
  ]},
 {id:"ex7",n:7,week:4,title:"Marking Like an Examiner",mins:150,icon:"BarChart2",
  summary:"How to use levels of response, examiner comments and common-mistake lists to mark student work reliably and give targeted feedback.",
  keyWords:["levels of response","examiner comment","common mistakes","targeted feedback","standardisation"],
  sections:[
   {h:"Read the whole answer, then place the level",art:"mark",p:[
    "Levels-of-response marking means reading the entire answer before deciding, then matching it to the level descriptor it best fits \u2014 not adding up ticks. Ask: is it one-sided or two-sided? Are points developed? Is there a reasoned conclusion?",
    "Teaching yourself to mark this way \u2014 holistically against descriptors \u2014 makes your marking match Cambridge\u2019s and makes your feedback more useful to students."],
    ex:{t:"Example \u2014 placing an answer in a level",b:["Two developed sides + a judged conclusion \u2192 top level.","Two sides but thin development \u2192 middle level.","One side, listed \u2192 lower level. Place first, fine-tune second."]}},
   {h:"Use the examiner comments as a marking guide",art:"read",p:[
    "The specimen \u2018examiner comments\u2019 model exactly the reasoning to copy: they praise signalled paragraphs, developed points, named studies and explicit links to the question, and they dock marks for undeveloped points, missing conclusions and weak links.",
    "Reading several of these comments trains your eye to see the same features in your own students\u2019 work, so your marking becomes faster and more consistent."],
    ex:{t:"Example \u2014 what the comments reward",b:["Praised: \u2018clearly signalled\u2019, \u2018well developed\u2019, \u2018named sociologists\u2019, \u2018linked to the question\u2019.","Docked: \u2018left implicit\u2019, \u2018not developed\u2019, \u2018no conclusion\u2019, \u2018merely described\u2019.","Mark your students against the same phrases."]}},
   {h:"Turn common mistakes into feedback",art:"talk",p:[
    "Each specimen answer ends with a \u2018common mistakes\u2019 list \u2014 a ready-made feedback bank. The same faults recur: undeveloped points, missing signal words, no conclusion, wasted introductions, ignoring context, and evaluating when only explanation was asked.",
    "Building your feedback around these named faults gives students precise, actionable targets (\u2018develop your third point\u2019, \u2018add a judged conclusion\u2019) instead of vague comments."],
    ex:{t:"Example \u2014 vague vs targeted feedback",b:["Vague: \u2018Add more detail.\u2019","Targeted: \u2018Your third point is named but not developed \u2014 add a \u2018because\u2019 sentence with an example.\u2019","The targeted version comes straight from the common-mistakes lists."]}},
   {h:"A standardisation routine for a department",art:"steps",p:[
    "To mark reliably as a team, standardise: everyone marks the same two specimen-style answers independently, then compares against the specimen mark and examiner comment, and discusses any differences until they agree.",
    "Repeating this before each big marking round keeps a whole department close to the Cambridge standard \u2014 and makes grades fair across classes."],
    ex:{t:"Example \u2014 a 30-minute standardisation",b:["All teachers mark the same two answers alone.","Compare marks and reasons against the specimen.","Agree a shared standard before marking your own classes."]}},
  ],
  activity:"Take one specimen essay and its examiner comment. Cover the mark, mark it yourself against the level descriptors, then compare. Note any gap between your mark and the specimen, and why.",
  check:[
   {q:"Levels-of-response marking means\u2026",o:["Matching the whole answer to a level descriptor","Timing the student","Counting ticks per fact","Marking only the conclusion"],a:0},
   {q:"The specimen \u2018common mistakes\u2019 lists are useful because they\u2026",o:["Provide a ready bank of targeted feedback","Replace the syllabus","Give the answers away","Are only for students"],a:0},
   {q:"Departmental standardisation mainly improves\u2026",o:["Handwriting","Class size","Exam length","Consistency and fairness of marking"],a:3},
  ]},
 {id:"ex8",n:8,week:4,title:"Building an Exam-Technique Scheme of Work",mins:150,icon:"BookOpen",
  summary:"How to weave command-word practice, timed writing and specimen marking into a term so technique improves alongside content.",
  keyWords:["scheme of work","command-word drills","timed practice","past papers","feedback loop"],
  sections:[
   {h:"Teach technique alongside content, not after",art:"steps",p:[
    "Exam technique should not be saved for the final weeks. The most effective approach threads command-word practice through every topic: each time a concept is taught, students immediately practise a [6] Explain or an [8] Discuss using it.",
    "This way, by the time revision arrives, students already own the structures \u2014 revision becomes polishing, not panic."],
    ex:{t:"Example \u2014 embedding technique in a topic",b:["Teach \u2018labelling theory\u2019 as content.","Immediately set: \u2018Explain three criticisms of labelling theory.\u2019 [6]","Content and technique are learned together."]}},
   {h:"A weekly rhythm of drills",art:"write",p:[
    "A simple weekly rhythm keeps technique sharp: a short [2]/[4] warm-up drill, one [6] Explain modelled and marked, and a fortnightly [8] or [14] essay done under timed conditions. Rotate command words so every type is practised.",
    "Short, frequent practice beats occasional long mocks: students get more feedback cycles and internalise the structures faster."],
    ex:{t:"Example \u2014 a week of technique",b:["Mon: five [2] quick-fire questions (3 min).","Wed: one [6] Explain, modelled then written.","Fri (fortnightly): a timed [8] or [14] essay.","Each returned with feedback tied to the common-mistakes list."]}},
   {h:"Use timed conditions and real papers",art:"target",p:[
    "Students need to practise to time. The specimen and past papers show the exact mark tariffs, so students can rehearse spending time in proportion \u2014 more minutes on the [14] than the [2]. Timed practice also builds the stamina a two-hour paper needs.",
    "Mark timed work against the specimen standard and examiner comments so the feedback matches what real examiners reward."],
    ex:{t:"Example \u2014 proportioning time",b:["Roughly one mark per 1\u20131.5 minutes of writing.","A [14] essay deserves far more time than a [2] identify.","Practise this split until it becomes automatic."]}},
   {h:"Close the feedback loop",art:"talk",p:[
    "Technique improves through the loop: model a structure, students write, mark against the specimen standard, give targeted feedback from the common-mistakes bank, then students redraft one paragraph. Redrafting is where the learning sticks.",
    "Over a term this loop moves a whole class up the levels \u2014 not by teaching more content, but by teaching them to answer the command words the way the mark schemes reward."],
    ex:{t:"Example \u2014 the improvement loop in action",b:["Model an Evaluate conclusion \u2192 students write one \u2192 mark against the specimen.","Feedback: \u2018make the conclusion weigh the evidence\u2019.","Students redraft just that conclusion \u2192 the skill is embedded."]}},
  ],
  activity:"Plan a four-week technique cycle for one topic you teach. For each week, note the command-word drill, the modelled answer, and the timed essay \u2014 and how you will feed back using the common-mistakes lists.",
  check:[
   {q:"The most effective place for exam technique is\u2026",o:["After the exam","Never","Threaded through every topic","Only the final week"],a:2},
   {q:"Frequent short drills are better than rare long mocks because they give\u2026",o:["More feedback cycles","Fewer marks","Less practice","Longer answers"],a:0},
   {q:"The feedback loop ends most effectively with students\u2026",o:["Redrafting one paragraph","Filing the work away","Reading only","Starting a new topic"],a:0},
  ]},
];
