// ============================================================================
//  PAYMENT INTEGRATION — PAYSTACK
//  Live hosted payment page. The parent is redirected to Paystack's secure,
//  PCI-compliant checkout. Paystack collects card / bank / mobile-money there.
//  NOTE: Final settlement should be confirmed server-side via a Paystack
//  webhook (charge.success). This frontend optimistically marks the fee paid
//  on return; a backend reconciliation step is required for production trust.
// ============================================================================
const PAYSTACK_PAGE = "https://paystack.shop/pay/Mindklass";
// Optional: if you provision a public key + transaction API, set these and the
// app will use the Paystack Inline popup instead of a full-page redirect.
const PAYSTACK_PUBLIC_KEY = ""; // e.g. "pk_live_xxx" — leave blank to use the hosted page
// Build a redirect URL to the hosted page. Reference + amount are passed as
// query params so they appear in the Paystack dashboard for reconciliation.
function paystackUrl(fee, payerEmail){
  const ref = `MK-${fee.id}-${Date.now()}`;
  const params = new URLSearchParams({
    ref,
    amount: String(Math.round(fee.amount*100)), // kobo/cents
    ...(payerEmail?{email:payerEmail}:{}),
  });
  return { url: `${PAYSTACK_PAGE}?${params.toString()}`, ref };
}

// ============================================================================
//  PUSH NOTIFICATIONS — FIREBASE CLOUD MESSAGING (FCM)
//  To go live: (1) create a Firebase project, (2) paste the web config below,
//  (3) add your Web Push VAPID key, (4) deploy the service worker file
//  `firebase-messaging-sw.js` at your site root, (5) send pushes from your
//  backend with the Admin SDK / HTTP v1 API using the stored device tokens.
//  When FCM_ENABLED stays false (e.g. in this preview), the app falls back to
//  the in-app notification feed so nothing breaks.
// ============================================================================
const FCM_ENABLED = false; // flip to true in production once config is filled in
const FIREBASE_CONFIG = {
  apiKey: "YOUR_API_KEY",
  authDomain: "mindklass.firebaseapp.com",
  projectId: "mindklass",
  storageBucket: "mindklass.appspot.com",
  messagingSenderId: "YOUR_SENDER_ID",
  appId: "YOUR_APP_ID",
};
const FCM_VAPID_KEY = "YOUR_PUBLIC_VAPID_KEY";

// Lazily initialise FCM in the browser. Safe no-op if disabled or unsupported.
async function initFCM(onMessageCb){
  if(!FCM_ENABLED || typeof window==="undefined") return null;
  try{
    // Loaded from CDN at runtime so the artifact has no build-time dependency.
    const appMod = await import("https://www.gstatic.com/firebasejs/10.12.0/firebase-app.js");
    const msgMod = await import("https://www.gstatic.com/firebasejs/10.12.0/firebase-messaging.js");
    const app = appMod.initializeApp(FIREBASE_CONFIG);
    const messaging = msgMod.getMessaging(app);
    const perm = await Notification.requestPermission();
    if(perm!=="granted") return null;
    const reg = await navigator.serviceWorker.register("/firebase-messaging-sw.js");
    const token = await msgMod.getToken(messaging,{ vapidKey:FCM_VAPID_KEY, serviceWorkerRegistration:reg });
    // Send `token` to your backend so it can target this device.
    if(token){ try{ await fetch("/api/register-push-token",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({token})}); }catch{} }
    // Foreground messages -> surface in the in-app feed too.
    msgMod.onMessage(messaging,(payload)=>{ onMessageCb&&onMessageCb(payload?.notification||{}); });
    return { messaging, token };
  }catch(e){ return null; }
}
// Ask the backend to broadcast a push to an audience. No-op without backend.
async function sendFcmBroadcast(payload){
  if(!FCM_ENABLED) return false;
  try{
    const r = await fetch("/api/send-push",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(payload)});
    return r.ok;
  }catch{ return false; }
}




// ============================================================================
//  OFFLINE-FIRST ENGINE
//  Designed for learners on poor / intermittent / zero connectivity.
//  - Caches all learning content (lessons, games, quizzes) to localStorage
//    so it is fully usable offline once visited.
//  - Queues student activity (XP, quiz results, messages, lesson completions)
//    in a durable outbox while offline.
//  - Auto-syncs the outbox to the "server" the moment connectivity returns.
//  - Lightweight: text-only payloads, tiny footprint, works on 2G / low data.
// ============================================================================
const OFFLINE_CACHE_KEY = "mk_offline_content_v1";
const OUTBOX_KEY        = "mk_sync_outbox_v1";

// Seed the offline content cache once, so lessons/games work with no network.
function seedOfflineCache(){
  try{
    if(!localStorage.getItem(OFFLINE_CACHE_KEY)){
      const pack = {
        cachedAt: Date.now(),
        lessons: LESSONS.map(l=>({t:l.t,body:l.body,done:l.done})),
        games:   GAMES.map(g=>({id:g.id,name:g.name,sub:g.sub})),
        gameQuestions: GQS,
        quizzes: QBANK,
        courses: COURSES.map(c=>({sub:c.sub,name:c.name,units:c.units,done:c.done})),
      };
      localStorage.setItem(OFFLINE_CACHE_KEY, JSON.stringify(pack));
    }
  }catch{}
}
function getOutbox(){ try{ return JSON.parse(localStorage.getItem(OUTBOX_KEY)||"[]"); }catch{ return []; } }
function saveOutbox(q){ try{ localStorage.setItem(OUTBOX_KEY, JSON.stringify(q)); }catch{} }

// React hook: connectivity + durable sync outbox.
function useOfflineSync(){
  const [online,setOnline]=useState(typeof navigator!=="undefined"?navigator.onLine:true);
  const [outbox,setOutbox]=useState(()=>getOutbox());
  const [syncing,setSyncing]=useState(false);
  const [lastSync,setLastSync]=useState(()=>{try{return localStorage.getItem("mk_last_sync");}catch{return null;}});

  useEffect(()=>{ seedOfflineCache(); },[]);

  // Queue an activity item (persists immediately, survives refresh / app close).
  const queueActivity=(type,payload)=>{
    setOutbox(prev=>{
      const next=[...prev,{id:Date.now()+Math.random(),type,payload,ts:new Date().toISOString(),synced:false}];
      saveOutbox(next);
      return next;
    });
  };

  // "Sync" the outbox. In production this POSTs to the API; here it simulates
  // a successful flush and stamps the sync time. Only runs when online.
  const flush=()=>{
    const pending=getOutbox().filter(i=>!i.synced);
    if(!pending.length) return;
    setSyncing(true);
    setTimeout(()=>{
      const cleared=getOutbox().map(i=>({...i,synced:true}));
      saveOutbox(cleared);
      setOutbox(cleared);
      const t=new Date().toLocaleString();
      try{localStorage.setItem("mk_last_sync",t);}catch{}
      setLastSync(t);
      setSyncing(false);
    },1400);
  };

  useEffect(()=>{
    const goOnline=()=>{ setOnline(true); };
    const goOffline=()=>{ setOnline(false); };
    window.addEventListener("online",goOnline);
    window.addEventListener("offline",goOffline);
    return()=>{ window.removeEventListener("online",goOnline); window.removeEventListener("offline",goOffline); };
  },[]);

  // Auto-flush whenever we come (back) online and have pending items.
  useEffect(()=>{ if(online) { const p=getOutbox().filter(i=>!i.synced); if(p.length) flush(); } },[online]);

  const pendingCount=outbox.filter(i=>!i.synced).length;
  return { online, pendingCount, syncing, lastSync, queueActivity, flush, outbox };
}

// Banner shown across the app reflecting connection + sync state.
function ConnectionBar({sync,T}){
  const { online, pendingCount, syncing, lastSync, flush } = sync;
  if(online && pendingCount===0 && !syncing){
    return (
      <div style={{display:"flex",alignItems:"center",gap:6,padding:"5px 11px",borderRadius:99,background:"#dcfce7",color:"#059669",fontSize:10,fontWeight:700,width:"fit-content"}}>
        <Wifi size={11}/>Online{lastSync?` · synced ${lastSync.split(",")[1]||""}`:" · all saved"}
      </div>
    );
  }
  if(!online){
    return (
      <div style={{display:"flex",alignItems:"center",gap:7,padding:"6px 12px",borderRadius:10,background:"#fffbeb",border:"1px solid #fde68a",color:"#92400e",fontSize:11,fontWeight:700,width:"fit-content"}}>
        <WifiOff size={13}/>Offline mode — keep learning! {pendingCount>0?`${pendingCount} update${pendingCount>1?"s":""} will sync when you reconnect.`:"Your work is saved on this device."}
      </div>
    );
  }
  // online + pending or syncing
  return (
    <div style={{display:"flex",alignItems:"center",gap:8,padding:"6px 12px",borderRadius:10,background:"#dbeafe",border:"1px solid #93c5fd",color:"#1842a8",fontSize:11,fontWeight:700,width:"fit-content"}}>
      <RotateCw size={13} style={{animation:syncing?"mkspin 1s linear infinite":"none"}}/>
      {syncing?`Syncing ${pendingCount} update${pendingCount>1?"s":""}...`:`${pendingCount} update${pendingCount>1?"s":""} pending`}
      {!syncing&&<button onClick={flush} style={{background:"#1842a8",color:"white",border:"none",borderRadius:7,padding:"2px 9px",fontSize:10,fontWeight:700,cursor:"pointer"}}>Sync now</button>}
      <style>{"@keyframes mkspin{from{transform:rotate(0)}to{transform:rotate(360deg)}}"}</style>
    </div>
  );
}

