    const cls=classes.find(c=>c.id===newAsg.classId);
    const {error}=await supabase.from("assignments").insert({class_id:newAsg.classId,subject:cls?.sub,teacher_id:user.id,title:newAsg.title,description:newAsg.desc,due_date:newAsg.due,points:Number(newAsg.points)||20,attachment:null});
    if(error){alert("Couldn't post the assignment: "+error.message);return;}
